import { Component } from '@angular/core';
import { ProductService } from '../product.service';
import { Product } from '../Model';

@Component({
  selector: 'products',
  templateUrl: './products.component.html',
  styleUrls: ['./products.component.css']
})
export class ProductsComponent{

  selectedProduct: Product | null; //buradki seçmiş olduğumuz Product bilgisini başka bir componente imput olarak göndermemiz gerekiyor.
  products: Product[];


  constructor(private productService: ProductService) {
    this.selectedProduct = null;
    this.products = [];
  }

  //constructerden hemen sonra çalışan method (constructorda servis çağırımı yapılıyor sonra bu çalıştırılıyor)
  ngOnInit():void{
    this.getProducts(); //yukarıdaki products listesinin dolmasını sağlıyor
  }


  getProducts(){
    this.productService.getProducts().subscribe(products =>
      {
        this.products=products;
      });
  }

  onSelectedProduct(product: Product){
    this.selectedProduct= product;
  }

  deleteProduct(product: Product){
  this.productService.deleteProduct(product);
  }
}
<div calass="container" style="margin-top: 100px">
  <div class="row">
    <div class="col-md-7">
      <table class="table table-bordered table-striped">
        <thead>
          <tr>
            <th>Id</th>
            <th>Name</th>
            <th>Price</th>
            <th></th>

          </tr>
        </thead>
        <tbody>
          <!-- burada isActive değerinin false olmasına göre tr tagına .bg-secondary clasını ekle yağıyoruz(ilgili satırların zeminlerinin gri olması gerekiyor) -->
          <tr *ngFor="let p of products" [class.bg-secondary]="p.isActive==false">
            <td>{{p.productId}}</td>
            <td>{{p.name}}</td>
            <td>{{p.price}}</td>
            <td>
               <button class="btn btn-primary" (click)="onSelectedProduct(p)"> Edit</button>
               <button class="btn btn-danger" (click)="deleteProduct(p)"> Delete</button>
            </td>
          </tr>
        </tbody>
      </table>
    </div>
    <div class="col-md-5">

      <product-details [product]="selectedProduct"></product-details>
      <!-- burda product-details'e parametre olarak gönderiyoruz ve product-details.ts içerisinde karşılıyoruz. -->

      <hr class="my-3">

      <product-form></product-form>

    </div>
  </div>
</div>
